template<class T>

V<T> VF(V<T> v, function<T(T)> f){

  int n = (int) v.size();

  V<T> ret(n);

  for(int i=0; i<n; ++i) {

    T a = v[i];

    ret[i] = f(a);

  }

  return ret;

}

