constexpr ll mod = 1000000007;



ll modpow(ll a, ll n, ll m) {

	ll res = 1;

	while (n) {

		if (n & 1)res = res * a % m;

		a = a * a%m; n >>= 1;

	}

	return res;

}



void solve(){

  ll n, k; cin >> n >> k;

  ll ans = 0, n2=0, n3=0, k2=0, k3=0;

  n2 = (n*n)%mod;

  n3 = (n2*n) % mod;

  k2 = (k*k) % mod;

  k3 = (k2*k) % mod;

  ans = (n3 + 3*n2 + (-3*k2 + 3*k + 8+1000*mod)*n%mod  + 2*k3 - (6*k2)%mod - (2*k)%mod +12 + 1000*mod ) % mod;

  (ans *= modpow(6,mod-2,mod)) %= mod;

  coutn(ans);

}











